// Fetch all 4 RSS feeds in parallel (public URLs, no auth needed)
const feeds = [
  { url: 'https://feeds.elpais.com/mrss-s/pages/ep/site/elpais.com/section/economia/portada', name: 'El País' },
  { url: 'https://www.europapress.es/rss/rss.aspx?ch=136', name: 'Europa Press' },
  { url: 'https://cincodias.elpais.com/rss/feed.html?feedId=17066', name: 'Cinco Días' },
  { url: 'https://www.boe.es/rss/canal.php?c=ayudas', name: 'BOE Ayudas' }
];

const results = await Promise.all(feeds.map(async (feed) => {
  try {
    const resp = await fetch(feed.url, { signal: AbortSignal.timeout(15000) });
    return { name: feed.name, text: await resp.text(), ok: true };
  } catch (e) {
    console.log(`[RSS] Error fetching ${feed.name}: ${e.message}`);
    return { name: feed.name, text: '', ok: false };
  }
}));

const newsXml = results.filter(r => r.name !== 'BOE Ayudas').map(r => r.text).join('\n');
const boeXml = results.find(r => r.name === 'BOE Ayudas')?.text || '';
const feedStatus = results.map(r => `${r.name}: ${r.ok ? 'OK' : 'FAIL'}`);

console.log(`[RSS] Feeds fetched: ${feedStatus.join(', ')}`);

return [{ json: { newsXml, boeXml, feedStatus } }];

// Split users into individual items for per-user processing
const usersResp = $('List Active Users').first().json;

if (!usersResp.ok || !usersResp.users || usersResp.users.length === 0) {
  console.log('[ENLAZE] No active users found — skipping');
  return [{ json: { _skip: true, reason: 'No active users' } }];
}

console.log(`[ENLAZE] Splitting ${usersResp.users.length} user(s) for processing`);

return usersResp.users.map(u => ({ json: { user_id: u.user_id, business_name: u.business_name, business_type: u.business_type, city: u.city } }));

// Parse and filter news RSS using this user's keywords + rss_filter_hints
const rssData = $('Fetch RSS Feeds').first().json;
const items = $input.all();

function parseRSS(xml) {
  const out = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml)) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s)||[])[1]||'';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s)||[])[1]||'';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s)||[])[1]||'';
    const pubDate = (b.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s)||[])[1]||'';
    let src = 'Desconocido';
    if (link.includes('elpais')) src = 'El País';
    else if (link.includes('europapress')) src = 'Europa Press';
    else if (link.includes('cincodias')) src = 'Cinco Días';
    out.push({ title: title.trim(), link: link.trim(), desc: desc.trim(), pubDate: pubDate.trim(), source: src });
  }
  return out;
}
function strip(s) { return s.replace(/<[^>]*>/g,'').replace(/&[a-z]+;/gi,' ').trim(); }

const allNewsItems = parseRSS(rssData.newsXml || '');

const results = [];
for (const item of items) {
  const config = item.json;
  const baseKw = ['comercio local','pyme','autónomo','subvención','digitalización','hostelería','iva','kit digital','empleo','inflación','consumo','energía','impuesto'];
  const userKw = (config.keywords || []).map(k => k.toLowerCase());
  const hints = (config.rss_filter_hints || []).map(k => k.toLowerCase());
  const allKw = [...new Set([...baseKw, ...userKw, ...hints])];

  const news = allNewsItems.map(i => {
    const text = (i.title+' '+i.desc).toLowerCase();
    let score = 0;
    for (const kw of allKw) { if (text.includes(kw)) score += 3; }
    score = Math.min(score, 10);
    return {
      id: 'news_'+Buffer.from(i.link||i.title).toString('base64').slice(0,12),
      title: strip(i.title), summary: strip(i.desc).slice(0,300),
      source: i.source, url: i.link,
      date: i.pubDate ? new Date(i.pubDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0],
      category: 'noticias', relevance: score,
      tags: allKw.filter(kw => text.includes(kw))
    };
  }).filter(n => n.relevance >= 3).sort((a,b) => b.relevance - a.relevance).slice(0,15);

  results.push({ json: { ...config, _news: news } });
}
return results;

// Parse and filter BOE ayudas/regulations using this user's keywords
const rssData = $('Fetch RSS Feeds').first().json;
const items = $input.all();

function parseRSS(xml) {
  const out = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml)) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s)||[])[1]||'';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s)||[])[1]||'';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s)||[])[1]||'';
    out.push({ title: title.trim(), link: link.trim(), desc: desc.trim() });
  }
  return out;
}
function strip(s) { return s.replace(/<[^>]*>/g,'').replace(/&[a-z]+;/gi,' ').trim(); }

const allBoeItems = parseRSS(rssData.boeXml || '');

const results = [];
for (const item of items) {
  const config = item.json;
  const userKw = (config.keywords || []).map(k => k.toLowerCase());
  const allKw = [...new Set([...userKw, 'pyme','comercio','digitalización','kit digital','autónomo','empleo','formación','subvención','ayuda','hostelería','turismo'])];

  const subsidies = [], regulations = [];
  for (const i of allBoeItems) {
    const text = (i.title+' '+i.desc).toLowerCase();
    if (!allKw.some(kw => text.includes(kw))) continue;
    const ct = strip(i.title), cd = strip(i.desc);
    if (text.includes('normativa')||text.includes('reglamento')||text.includes('obligación')||text.includes('ley ')) {
      regulations.push({ id:'reg_'+Buffer.from(i.link||i.title).toString('base64').slice(0,12), title:ct, type:'normativa', summary:cd.slice(0,300), url:i.link, impact:'medium', action_required:'Revisar requisitos y plazos' });
    } else {
      let type = 'ayuda';
      if (text.includes('subvención')) type = 'subvención';
      else if (text.includes('formación')) type = 'formación';
      subsidies.push({ id:'sub_'+Buffer.from(i.link||i.title).toString('base64').slice(0,12), title:ct, type, amount_range:'', deadline:'', target:'Pymes y autónomos', url:i.link, status:'abierta' });
    }
  }

  results.push({ json: { ...config, _subsidies: subsidies.slice(0,10), _regulations: regulations.slice(0,10) } });
}
return results;

// Generate marketing ideas based on business_type, calendar, and marketing_hints
const items = $input.all();
const now = new Date();
const month = now.getMonth()+1;
const dates30 = [];
for (let i=0;i<30;i++) {
  const d = new Date(now.getTime()+i*86400000);
  dates30.push({date:d, m:d.getMonth()+1, d:d.getDate(), dow:d.getDay()});
}
const calendar = [
  {m:1,d:6,name:'Reyes',for:['tienda','comercio']},
  {m:2,d:14,name:'San Valentín',for:['restaurante','bar','estetica','peluqueria','floristeria']},
  {m:3,d:8,name:'Día de la Mujer',for:['estetica','peluqueria']},
  {m:3,d:19,name:'Día del Padre',for:['tienda','restaurante','bar','peluqueria']},
  {m:5,d:1,name:'Día del Trabajador',for:['todos']},
  {m:5,d:4,name:'Día de la Madre',for:['tienda','restaurante','estetica','peluqueria','floristeria']},
  {m:6,d:21,name:'Inicio Verano',for:['todos']},
  {m:9,d:1,name:'Vuelta al cole',for:['tienda','peluqueria']},
  {m:10,d:31,name:'Halloween',for:['bar','restaurante','tienda']},
  {m:11,d:25,name:'Black Friday',for:['todos']},
  {m:12,d:25,name:'Navidad',for:['todos']},
  {m:12,d:31,name:'Nochevieja',for:['restaurante','bar']}
];
const norm = s => s.normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const results = [];
for (const item of items) {
  const config = item.json;
  const bizType = norm((config.business_type||'comercio').toLowerCase());
  const bizName = config.business_name || 'Mi Negocio';
  const mHints = config.marketing_hints || [];
  const campaigns = [], upcoming = [];

  for (const e of calendar) {
    for (const d of dates30) {
      if (d.m===e.m && d.d===e.d && (e.for.includes('todos')||e.for.some(t=>bizType.includes(t)))) {
        const ds = d.date.toISOString().split('T')[0];
        upcoming.push({name:e.name, date:ds});
        campaigns.push({title:`Campaña ${e.name}`, type:'promotion', channel:['whatsapp','instagram'], target_audience:'clientes_recurrentes', suggested_date:ds, message_draft:`¡${e.name} se acerca! En ${bizName} tenemos algo especial.`, reason:`Fecha señalada: ${e.name}`});
      }
    }
  }
  if (['bar','restaurante','cafeteria','cafe'].some(t=>bizType.includes(t))) {
    const tue = dates30.find(d=>d.dow===2);
    if (tue) campaigns.push({title:'Promo martes — día valle', type:'promotion', channel:['whatsapp','instagram'], target_audience:'clientes_recurrentes', suggested_date:tue.date.toISOString().split('T')[0], message_draft:`¡Este martes en ${bizName} oferta especial!`, reason:'Día valle hostelería'});
  }
  if (mHints.length>0 && campaigns.length<3) {
    const hint = mHints[Math.floor(Math.random()*mHints.length)];
    campaigns.push({title:`Idea: ${hint}`, type:'content', channel:['instagram'], target_audience:'todos', suggested_date:dates30[3]?.date.toISOString().split('T')[0]||'', message_draft:`¡Novedad en ${bizName}! ${hint.charAt(0).toUpperCase()+hint.slice(1)}.`, reason:`Tipo negocio: ${config.business_type}`});
  }
  if (campaigns.length===0) {
    let idea = month>=6&&month<=8?'Campaña verano':month>=11||month<=1?'Campaña navideña':month>=3&&month<=5?'Campaña primavera':'Campaña otoño';
    campaigns.push({title:idea, type:'content', channel:['instagram'], target_audience:'todos', suggested_date:dates30[3]?.date.toISOString().split('T')[0]||'', message_draft:`¡Novedades en ${bizName}!`, reason:'Estacional'});
  }

  results.push({ json: { ...config, _campaigns: campaigns, _upcoming: upcoming } });
}
return results;

// Build the final payload per user for /api/agent/ingest
const items = $input.all();
const now = new Date().toISOString();

const results = [];
for (const item of items) {
  const c = item.json;
  const news = c._news || [];
  const subsidies = c._subsidies || [];
  const regulations = c._regulations || [];
  const campaigns = c._campaigns || [];

  const nc=news.length, sc=subsidies.length, rc=regulations.length, cc=campaigns.length;
  let headline = `Hoy tienes ${nc} noticias relevantes`;
  if (sc>0) headline += `, ${sc} ayudas disponibles`;
  headline += '.';
  const actions = [];
  if (sc>0) actions.push(`Revisar ${sc} ayuda(s)/subvención(es)`);
  if (rc>0) actions.push(`Revisar ${rc} cambio(s) normativo(s)`);
  if (cc>0) actions.push(`Considerar ${cc} idea(s) de marketing`);
  const score = Math.max(0, Math.min(100, 40+nc*3+sc*8+cc*5-rc*5));

  const payload = {
    user_id: c.user_id,
    agent: 'comercio_local',
    version: '2.0',
    business_id: c.business_id || c.user_id,
    timestamp: now,
    daily_summary: { headline, priority_actions: actions, opportunities_count: sc+cc, risks_count: rc, score },
    radar: { news, regulations, subsidies, competitor_signals: [], local_events: [] },
    reputation: {
      reviews: { current_rating:0, total_reviews:0, trend:'unknown' },
      campaigns
    }
  };

  console.log(`[ENLAZE] Payload for ${c.business_name}: ${nc} news, ${sc} subsidies, ${cc} campaigns, score=${score}`);
  results.push({ json: payload });
}
return results;

// Log final results
const items = $input.all();
const results = items.map(item => {
  const r = item.json;
  const ok = r.success === true;
  console.log(`[ENLAZE] Result for user ${r.user_id}: success=${ok}`);
  return { json: { user_id: r.user_id, success: ok, timestamp: r.timestamp, results: r.results || {} } };
});

console.log(`[ENLAZE] Agent run complete. Processed ${results.length} user(s).`);
return results;
